function rpMelding(msg, level) {
    var el = document.getElementById('rpBevestiging');
    el.textContent = msg;
    el.style.display = 'block';
    var err = level === true || level === 'err';
    var warn = level === 'warn';
    if (err) {
        el.style.background = '#fde8e8';
        el.style.color = '#c81e1e';
    } else if (warn) {
        el.style.background = '#fff8e1';
        el.style.color = '#856404';
    } else {
        el.style.background = '#e8f5e9';
        el.style.color = '#2e7d32';
    }
    var ms = warn ? 7000 : 3000;
    setTimeout(function() { el.style.display = 'none'; }, ms);
}

